  ('heelevel3-988e0de1-moex-00031', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計之原理與原則，下列敘述何者正確？', '["特別收入基金以經濟資源流量為衡量焦點", "作業基金以經濟資源流量為衡量焦點", "國庫出納會計採權責發生基礎", "關稅徵課會計採現金收付基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00032', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '以估計之公允價值記載接受民間捐贈救護車或救災裝備器材等各類資產，係依政府會計準則公報 第1號規定之何種基本會計原則辦理？', '["配合原則", "收入（或收益）實現原則", "成本原則", "預算管理原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00033', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報第5號規定，下列關於政府長期股權投資之會計處理之敘述，正確者計有幾', '["長期股權投資不論是否具重大影響力，收到被投資者之現金股利時，皆應列為收入", "長 期股權投資不論是否具重大影響力，應於年度終了採權益法認列", "長期股權投資不論是否具重 大影響力，應按購買時之取得成本入帳", "0項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00034', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報第2號規定，中央政府乙機關於X8年度收到承包商A公司的違約金收入100萬元， 代地方政府徵收之契稅收入200萬元，某地方政府鐵路立體化建設計畫的配合款300萬元、自強愛國 捐獻收入400萬元，及核發駕駛執照之收入500萬元，則乙機關當年度應列記收入之數額若干？', '["1,000萬元", "1,200萬元", "1,300萬元", "1,500萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00035', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關向X公司承租一檢驗設備，該項設備係配合甲機關需求定製，製作完成後，甲機關無須修 改即可使用，設備耐用年限15年，無殘值，公允價值1億3,000萬元，因此雙方約定如下：⑴租期 10年，租金自租賃開始日起，每年支付1,500萬元（折現率3%）；⑵租期屆滿後，甲機關可繼續使 用3個月，3個月後須決定按每年租金1,200萬元續租5年或以5,000萬元優先購入該設備或不再租 用。依政府會計準則公報第4號規定，針對該租賃合約，下列敘述何者正確？', '["該項租賃為非融資租賃，因為各期給付租金之現值總額未達該設備幾乎所有公允價值", "該項租賃為非融資租賃，因為尚無法確定於租金屆滿前是否享有優先續租權或優惠承購權", "該項租賃為融資租賃，因為租賃期間為15年3個月，已超過該設備的耐用年限", "該項租賃為融資租賃，因為該項設備為客製化設備，且無須修改即可使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
