  ('heelevel3-988e0de1-moex-00037', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央總會計制度之規定，下列基金何者應編製特種基金財務報表及其附註？①內部服務基金', '["營業基金", "代理基金", "信託基金  ⑤債務基金", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ca304502c292", "answer_pdf_sha1": "9c0d38d9680e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
